<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>2048</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html, body { height: 100%; }
  body {
    background: #0f0f14;
    color: #e8e6e3;
    font-family: "Segoe UI", Arial, Helvetica, sans-serif;
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    padding: 16px;
  }
  .wrap {
    width: min(92vw, 460px);
    display: flex;
    flex-direction: column;
    align-items: stretch;
    gap: 14px;
  }
  header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
  }
  h1 {
    font-size: 2.4rem;
    font-weight: 800;
    letter-spacing: 1px;
    color: #edc22e;
  }
  .panel {
    display: flex;
    align-items: center;
    gap: 12px;
  }
  .score-box {
    background: #1d1d26;
    border: 1px solid #2c2c38;
    border-radius: 8px;
    padding: 8px 16px;
    text-align: center;
    min-width: 110px;
  }
  .score-box .label {
    display: block;
    font-size: 0.7rem;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: #9a97a5;
  }
  #score {
    display: block;
    font-size: 1.4rem;
    font-weight: 800;
    color: #ffffff;
  }
  #reset {
    background: #8f7a66;
    color: #f9f6f2;
    border: none;
    border-radius: 8px;
    padding: 12px 18px;
    font-size: 0.95rem;
    font-weight: 700;
    cursor: pointer;
    transition: background 0.15s ease, transform 0.05s ease;
  }
  #reset:hover { background: #9f8b76; }
  #reset:active { transform: scale(0.97); }
  #board {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 10px;
    background: #1b1b23;
    border: 1px solid #2c2c38;
    border-radius: 10px;
    padding: 10px;
    width: 100%;
  }
  .cell {
    aspect-ratio: 1 / 1;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 7px;
    background: #26262f;
    font-size: 2rem;
    font-weight: 800;
    color: #776e65;
    user-select: none;
  }
  .cell.small { font-size: 1.5rem; }
  .cell.v2    { background: #eee4da; }
  .cell.v4    { background: #ede0c8; }
  .cell.v8    { background: #f2b179; color: #f9f6f2; }
  .cell.v16   { background: #f59563; color: #f9f6f2; }
  .cell.v32   { background: #f67c5f; color: #f9f6f2; }
  .cell.v64   { background: #f65e3b; color: #f9f6f2; }
  .cell.v128  { background: #edcf72; color: #f9f6f2; }
  .cell.v256  { background: #edcc61; color: #f9f6f2; }
  .cell.v512  { background: #edc850; color: #f9f6f2; }
  .cell.v1024 { background: #edc53f; color: #f9f6f2; }
  .cell.v2048 { background: #edc22e; color: #f9f6f2; box-shadow: 0 0 18px rgba(237,194,46,0.45); }
  .cell.vsuper { background: #3c3a32; color: #f9f6f2; }
  .hint {
    text-align: center;
    font-size: 0.85rem;
    color: #8b8896;
  }
  #message {
    text-align: center;
    font-size: 1rem;
    font-weight: 700;
    color: #f67c5f;
    min-height: 1.2em;
  }
</style>
</head>
<body>
  <div class="wrap">
    <header>
      <h1>2048</h1>
      <div class="panel">
        <div class="score-box">
          <span class="label">Score</span>
          <span id="score">0</span>
        </div>
        <button id="reset" type="button">New Game</button>
      </div>
    </header>
    <div id="board" aria-label="2048 board"></div>
    <div id="message"></div>
    <p class="hint">Use the arrow keys to slide tiles. Matching tiles merge.</p>
  </div>

<script>
(function () {
  'use strict';

  var SIZE = 4;
  var grid = [];
  var scoreVal = 0;

  var boardEl = document.getElementById('board');
  var scoreEl = document.getElementById('score');
  var resetBtn = document.getElementById('reset');
  var messageEl = document.getElementById('message');

  function emptyGrid() {
    var g = [];
    for (var r = 0; r < SIZE; r++) {
      var row = [];
      for (var c = 0; c < SIZE; c++) row.push(0);
      g.push(row);
    }
    return g;
  }

  function emptyCells() {
    var cells = [];
    for (var r = 0; r < SIZE; r++)
      for (var c = 0; c < SIZE; c++)
        if (grid[r][c] === 0) cells.push([r, c]);
    return cells;
  }

  function spawn() {
    var cells = emptyCells();
    if (cells.length === 0) return false;
    var pick = cells[Math.floor(Math.random() * cells.length)];
    grid[pick[0]][pick[1]] = Math.random() < 0.9 ? 2 : 4;
    return true;
  }

  // Slide a 4-element line toward index 0, merging equal neighbours once each.
  function slideLine(line) {
    var nums = [];
    for (var i = 0; i < line.length; i++)
      if (line[i] !== 0) nums.push(line[i]);
    var out = [];
    var gained = 0;
    for (var j = 0; j < nums.length; j++) {
      if (j + 1 < nums.length && nums[j] === nums[j + 1]) {
        var merged = nums[j] * 2;
        out.push(merged);
        gained += merged;
        j++; // consume the partner; it cannot merge again this move
      } else {
        out.push(nums[j]);
      }
    }
    while (out.length < SIZE) out.push(0);
    return { line: out, gained: gained };
  }

  // Read line i in movement order: index 0 is the edge tiles travel toward.
  function getLine(g, dir, i) {
    if (dir === 'left')  return [g[i][0], g[i][1], g[i][2], g[i][3]];
    if (dir === 'right') return [g[i][3], g[i][2], g[i][1], g[i][0]];
    if (dir === 'up')    return [g[0][i], g[1][i], g[2][i], g[3][i]];
    return                      [g[3][i], g[2][i], g[1][i], g[0][i]]; // down
  }

  function setLine(g, dir, i, line) {
    if (dir === 'left') {
      g[i][0] = line[0]; g[i][1] = line[1]; g[i][2] = line[2]; g[i][3] = line[3];
    } else if (dir === 'right') {
      g[i][3] = line[0]; g[i][2] = line[1]; g[i][1] = line[2]; g[i][0] = line[3];
    } else if (dir === 'up') {
      g[0][i] = line[0]; g[1][i] = line[1]; g[2][i] = line[2]; g[3][i] = line[3];
    } else { // down
      g[3][i] = line[0]; g[2][i] = line[1]; g[1][i] = line[2]; g[0][i] = line[3];
    }
  }

  function move(dir) {
    if (dir !== 'left' && dir !== 'right' && dir !== 'up' && dir !== 'down')
      return false;

    var next = emptyGrid();
    var gained = 0;
    for (var i = 0; i < SIZE; i++) {
      var res = slideLine(getLine(grid, dir, i));
      gained += res.gained;
      setLine(next, dir, i, res.line);
    }

    var changed = false;
    for (var r = 0; r < SIZE && !changed; r++)
      for (var c = 0; c < SIZE; c++)
        if (grid[r][c] !== next[r][c]) { changed = true; break; }

    if (!changed) return false; // no movement: no spawn, no score change

    grid = next;
    scoreVal += gained;
    spawn();
    render();
    return true;
  }

  function reset() {
    grid = emptyGrid();
    scoreVal = 0;
    spawn();
    spawn();
    render();
  }

  function setBoard(arr) {
    grid = emptyGrid();
    for (var r = 0; r < SIZE; r++)
      for (var c = 0; c < SIZE; c++) {
        var v = (arr && arr[r] && typeof arr[r][c] === 'number' && isFinite(arr[r][c]))
          ? Math.trunc(arr[r][c]) : 0;
        grid[r][c] = v > 0 ? v : 0;
      }
    scoreVal = 0;
    render();
  }

  function movesAvailable() {
    if (emptyCells().length > 0) return true;
    for (var r = 0; r < SIZE; r++)
      for (var c = 0; c < SIZE; c++) {
        if (c + 1 < SIZE && grid[r][c] === grid[r][c + 1]) return true;
        if (r + 1 < SIZE && grid[r][c] === grid[r + 1][c]) return true;
      }
    return false;
  }

  function render() {
    scoreEl.textContent = String(scoreVal);
    boardEl.innerHTML = '';
    for (var r = 0; r < SIZE; r++) {
      for (var c = 0; c < SIZE; c++) {
        var v = grid[r][c];
        var d = document.createElement('div');
        d.className = 'cell';
        if (v !== 0) {
          d.className += v <= 2048 ? ' v' + v : ' vsuper';
          if (v >= 1024) d.className += ' small';
          d.textContent = String(v);
        }
        d.setAttribute('data-value', String(v));
        boardEl.appendChild(d);
      }
    }
    messageEl.textContent = movesAvailable() ? '' : 'Game over — press New Game to play again.';
  }

  window.addEventListener('keydown', function (e) {
    var dir = null;
    if (e.key === 'ArrowLeft') dir = 'left';
    else if (e.key === 'ArrowRight') dir = 'right';
    else if (e.key === 'ArrowUp') dir = 'up';
    else if (e.key === 'ArrowDown') dir = 'down';
    if (!dir) return;
    e.preventDefault();
    move(dir);
  });

  resetBtn.addEventListener('click', reset);

  window.game = {
    size: SIZE,
    reset: reset,
    move: move,
    board: function () { return grid.map(function (row) { return row.slice(); }); },
    setBoard: setBoard,
    score: function () { return scoreVal; }
  };

  reset();
})();
</script>
</body>
</html>
